//create flash for player appearance
void create_player_appearance_effect(object* player_obj)
{
	vms_vector pos;
	object* effect_obj;

#ifndef NDEBUG
	{
		int objnum = player_obj - Objects;
		if ((objnum < 0) || (objnum > Highest_object_index))
