{
	int i;

	// 'Remove' the unused players
#ifdef NETWORK
	if (Game_mode & GM_MULTI)
	{
		for (i = 0; i < NumNetPlayerPositions; i++)
		{
			if ((!Players[i].connected) || (i >= N_players))
