						// -- "9.	Find the exit" CC_LSPACING_S "3\n"
				, goal_str, tstr);

	show_escort_menu(msg);		//TXT_PAUSE);
	plat_present_canvas(0);

	while (paused) 
	{
	#ifdef WINDOWS
		while (!(key = key_inkey()))
		{
			MSG wmsg;
			DoMessageStuff(&wmsg);
		}
	#else
		key = key_getch();
	#endif

		switch (key) 
		{
			case KEY_0:
			case KEY_1:
			case KEY_2:
			case KEY_3:
			case KEY_4:
			case KEY_5:
			case KEY_6:
			case KEY_7:
			case KEY_8:
			case KEY_9:
				Looking_for_marker = -1;
				Last_buddy_key = -1;
				set_escort_special_goal(key);
				Last_buddy_key = -1;
				paused = 0;
				break;

			case KEY_ESC:
			case KEY_ENTER:
				clear_boxed_message();
				paused=0;
				break;

//--10/08/95-- Screwed up font, background.  Why needed, anyway?
//--10/08/95--			case KEY_F1:
//--10/08/95-- 				clear_boxed_message();
//--10/08/95--				do_show_help();
//--10/08/95--				show_boxed_message(msg);
//--10/08/95--				break;

			case KEY_PRINT_SCREEN:
				save_screen_shot(0);
				break;

			#ifndef RELEASE
			case KEY_BACKSP: Int3(); break;
			#endif

			case KEY_T: 
			{
				char msg[32];
				int temp;

				temp = !Buddy_messages_suppressed;

				if (temp)
					strcpy(msg, "suppressed");
				else
					strcpy(msg, "enabled");

				Buddy_messages_suppressed = 1;
				buddy_message("Messages %s.", msg);

				Buddy_messages_suppressed = temp;

				paused = 0;
				break;
			}
			default:
				break;
		}
	}
